const payload = $('Webhook').first().json.body ?? $('Webhook').first().json;
const messages = $input.all().map((item) => item.json).filter((mail) => mail && (mail.id || mail.payload || mail.snippet));
const requestedLimit = Number(payload.limit ?? 10);
const limit = Number.isFinite(requestedLimit) && requestedLimit > 0 ? Math.min(requestedLimit, 30) : 10;
const groupByDate = String(payload.groupByDate ?? '').toLowerCase() === 'true';

if (!messages.length) {
  return [{ json: { reply: '조회 조건에 맞는 메일이 없습니다.', action: 'gmail-list', count: 0, hasMore: false, nextCursor: null, groupByDate, items: [] } }];
}

const readHeader = (headers, key) => {
  if (!Array.isArray(headers)) return '';
  const matched = headers.find((header) => String(header.name || '').toLowerCase() === key.toLowerCase());
  return matched?.value || '';
};

const parseDate = (rawDate, fallbackInternalDate) => {
  if (rawDate) {
    const parsed = new Date(rawDate);
    if (!Number.isNaN(parsed.getTime())) {
      return parsed;
    }
  }
  if (fallbackInternalDate) {
    const parsed = new Date(Number(fallbackInternalDate));
    if (!Number.isNaN(parsed.getTime())) {
      return parsed;
    }
  }
  return null;
};

const formatDateLabel = (date) => {
  if (!date) return '날짜 미상';
  return new Intl.DateTimeFormat('ko-KR', { year: 'numeric', month: '2-digit', day: '2-digit', weekday: 'short' }).format(date);
};

const items = messages.slice(0, limit).map((mail, index) => {
  const headers = mail.payload?.headers || [];
  const subject = mail.subject || readHeader(headers, 'Subject') || mail.snippet || '제목 없음';
  const sender = mail.from?.text || readHeader(headers, 'From') || '발신자 미상';
  const snippet = String(mail.snippet || '').substring(0, 160);
  const dateRaw = readHeader(headers, 'Date');
  const parsedDate = parseDate(dateRaw, mail.internalDate);
  const internalDate = mail.internalDate ? String(mail.internalDate) : (parsedDate ? String(parsedDate.getTime()) : '');
  const date = parsedDate ? parsedDate.toISOString() : dateRaw;
  const dateLabel = formatDateLabel(parsedDate);
  const unread = Array.isArray(mail.labelIds) ? mail.labelIds.includes('UNREAD') : false;
  const hasAttachments = String(mail.payload?.mimeType || '').includes('multipart');

  return {
    index: index + 1,
    messageId: String(mail.id || ''),
    threadId: String(mail.threadId || ''),
    sender,
    subject,
    snippet,
    date,
    dateLabel,
    internalDate,
    unread,
    hasAttachments,
  };
});

const grouped = {};
if (groupByDate) {
  for (const item of items) {
    const key = item.dateLabel || '날짜 미상';
    if (!grouped[key]) grouped[key] = [];
    grouped[key].push(item);
  }
}

const lines = [];
if (groupByDate) {
  Object.entries(grouped).forEach(([label, list]) => {
    lines.push(`📅 ${label}`);
    list.forEach((mail) => lines.push(`${mail.index}. ${mail.sender} - ${mail.subject}`));
    lines.push('');
  });
} else {
  items.forEach((mail) => lines.push(`${mail.index}. ${mail.sender} - ${mail.subject}`));
}

const hasMore = messages.length > items.length;
const nextCursor = hasMore ? String(items[items.length - 1]?.internalDate || '') : null;

return [{
  json: {
    reply: `최근 메일 목록입니다.\n${lines.join('\n').trim()}`,
    action: 'gmail-list',
    count: messages.length,
    shownCount: items.length,
    hasMore,
    nextCursor,
    groupByDate,
    items,
  },
}];
